# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.
# Category: insecure_universal_links

import UIKit

// MARK: - Universal Link Router

enum DeepLinkDestination {
    case passwordReset(token: String)
    case unknown
}

class UniversalLinkHandler {
    
    static let shared = UniversalLinkHandler()
    
    private let supportedHost = "myapp.com"
    private let resetPasswordPath = "/reset-password"
    
    private init() {}
    
    // MARK: - Parse Universal Link
    
    func handleUniversalLink(_ url: URL) -> DeepLinkDestination {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            print("[UniversalLinkHandler] Failed to parse URL: \(url)")
            return .unknown
        }
        
        guard components.host == supportedHost else {
            print("[UniversalLinkHandler] Unsupported host: \(components.host ?? "nil")")
            return .unknown
        }
        
        switch components.path {
        case resetPasswordPath:
            return parsePasswordResetLink(from: components)
        default:
            print("[UniversalLinkHandler] Unhandled path: \(components.path)")
            return .unknown
        }
    }
    
    private func parsePasswordResetLink(from components: URLComponents) -> DeepLinkDestination {
        guard let queryItems = components.queryItems,
              let token = queryItems.first(where: { $0.name == "token" })?.value,
              !token.isEmpty else {
            print("[UniversalLinkHandler] Missing or empty token in password reset link")
            return .unknown
        }
        
        return .passwordReset(token: token)
    }
    
    // MARK: - Navigation
    
    func navigateToDestination(_ destination: DeepLinkDestination, from window: UIWindow?) {
        guard let window = window else {
            print("[UniversalLinkHandler] No window available for navigation")
            return
        }
        
        switch destination {
        case .passwordReset(let token):
            navigateToPasswordReset(token: token, from: window)
        case .unknown:
            print("[UniversalLinkHandler] Cannot navigate to unknown destination")
        }
    }
    
    private func navigateToPasswordReset(token: String, from window: UIWindow) {
        let passwordResetVC = PasswordResetViewController(token: token)
        
        if let navigationController = findTopNavigationController(in: window) {
            // Dismiss any presented view controllers first
            if let presented = navigationController.presentedViewController {
                presented.dismiss(animated: false) {
                    navigationController.pushViewController(passwordResetVC, animated: true)
                }
            } else {
                navigationController.pushViewController(passwordResetVC, animated: true)
            }
        } else if let rootVC = window.rootViewController {
            let navController = UINavigationController(rootViewController: passwordResetVC)
            navController.modalPresentationStyle = .fullScreen
            
            if let presented = rootVC.presentedViewController {
                presented.dismiss(animated: false) {
                    rootVC.present(navController, animated: true)
                }
            } else {
                rootVC.present(navController, animated: true)
            }
        }
    }
    
    private func findTopNavigationController(in window: UIWindow) -> UINavigationController? {
        var topController = window.rootViewController
        
        while let presented = topController?.presentedViewController {
            topController = presented
        }
        
        if let navController = topController as? UINavigationController {
            return navController
        }
        
        if let tabBarController = topController as? UITabBarController,
           let navController = tabBarController.selectedViewController as? UINavigationController {
            return navController
        }
        
        return topController?.navigationController
    }
}

